import{_ as t,o as a,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Read the Audit Logs","description":"","frontmatter":{},"headers":[],"relativePath":"reference/audit-logs.md","filePath":"reference/audit-logs.md"}'),l={name:"reference/audit-logs.md"};function r(s,e,d,n,h,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="read-the-audit-logs" tabindex="-1">Read the Audit Logs <a class="header-anchor" href="#read-the-audit-logs" aria-label="Permalink to &quot;Read the Audit Logs&quot;">​</a></h1><p>This guide is for senior read-only review of the audit trail. It is useful for <code>Supreme Admin</code>, <code>King</code>, and <code>Alliance Leader</code> users who can open the logs page.</p><blockquote><p>Screenshot placeholder: <code>audit-logs.png</code> (S48)</p></blockquote><h2 id="what-the-audit-log-is-for" tabindex="-1">What the audit log is for <a class="header-anchor" href="#what-the-audit-log-is-for" aria-label="Permalink to &quot;What the audit log is for&quot;">​</a></h2><p>The audit log answers questions like:</p><ul><li>who changed this</li><li>what action happened</li><li>when it happened</li><li>what was hidden or redacted</li></ul><h2 id="how-to-read-one-entry" tabindex="-1">How to read one entry <a class="header-anchor" href="#how-to-read-one-entry" aria-label="Permalink to &quot;How to read one entry&quot;">​</a></h2><p>Each log entry should be read as a small story:</p><ul><li><strong>actor</strong>: who did it</li><li><strong>action</strong>: what they did</li><li><strong>timestamp</strong>: when it happened</li><li><strong>entity</strong>: what record it affected</li><li><strong>details</strong>: what changed, including any safe redaction</li></ul><p>Do not read the action label alone. The actor, target, and time are what turn it into something meaningful.</p><h2 id="redacted-fields" tabindex="-1">Redacted fields <a class="header-anchor" href="#redacted-fields" aria-label="Permalink to &quot;Redacted fields&quot;">​</a></h2><p>Some sensitive values are intentionally hidden or reduced in the audit log. That is expected behavior, not missing data.</p><p>The goal is accountability without exposing secrets.</p><h2 id="how-to-use-the-logs-well" tabindex="-1">How to use the logs well <a class="header-anchor" href="#how-to-use-the-logs-well" aria-label="Permalink to &quot;How to use the logs well&quot;">​</a></h2><ul><li>start with the time range you care about</li><li>look for the actor and target together</li><li>compare suspicious changes with related pages like users, plans, imports, or suspensions</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></li><li><a href="./../how-to/reports.html">File &amp; Track Reports</a></li></ul>',17)])])}const p=t(l,[["render",r]]);export{g as __pageData,p as default};
